sql:
SELECT dealership_id 
FROM vehicle_inventory 
WHERE stock_level > 0;

external_knowledge:
- "Latest vehicle models" refers to those with the most recent 'year' value; 
- "Specifications" include year, trim, transmission, fuel type, doors, seats, exterior color, interior color, and production date;
- "Inventory levels" encompass stock levels, reserved units, available units, and the last sold price;
- "Sales information" is inferred from the last sold price.

sql:
SELECT AVG(CAST(REPLACE(msrp, ',', '') AS REAL) - CAST(REPLACE(invoice_price, ',', '') AS REAL)) AS overall_avg_price_difference
FROM vehicles
WHERE YEAR > 2020 AND drive_train_id = 1;

SELECT msrp
FROM vehicles
WHERE drive_train_id = (SELECT drive_train_id FROM drive_trains WHERE drive_train_name = 'All');

SELECT MAX(stock_level) AS peak_stock_level
FROM vehicle_inventory
WHERE dealership_id = 1;
